-- ----------------------------------------------------------------------------
-- vw_roles: View for Roles
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_roles CASCADE;
CREATE VIEW vw_roles WITH (security_invoker = ON) AS
SELECT
  t.role_id,                                                                    -- PK = the canonical role token (REP / MANAGER / OPERATIONS / ADMIN).
  calc_roles_name(t.role_id) AS name,                                           -- Echoes RoleId.
  t.title,                                                                      -- Human-readable role title.
  t.description,                                                                -- What this role does / who holds it.
  t.default_crud,                                                               -- Role-level baseline CRUD grant (contains C/R/U/D). Table/Field perms inherit from this when NULL. e.g. Admin=CRUD.
  t.order_index,                                                                -- Sort order (REP=1 .. ADMIN=4).
  t.is_admin_equivalent,                                                        -- TRUE when this role gets admin-level nav visibility (ADMIN and OPERATIONS).
  t.is_redacted_role,                                                           -- DEFAULT redaction posture for this role. TRUE = a "redacted role": by default it gets NO CRUD on any field that has a "<Field>Redacted" sibling (e.g. SSN is denied when SSNRedacted exists). Flows down to every table; override per table+role via ERBTables.{Role}IsRedacted.
  calc_roles_app_users(t.role_id) AS app_users,                                 -- Reverse: app users holding this role.
  calc_roles_app_user_count(t.role_id) AS app_user_count,                       -- Count of AppUsers with this role.
  t.created_at,                                                                 -- Audit: when this row was first inserted. Auto-stamped by the audit trigger (now() on INSERT); immutable thereafter.
  t.created_by,                                                                 -- Audit: the OWNER — the JWT user (auth.email()) who created this row. Auto-stamped on INSERT; immutable thereafter. NULL for build-time seed rows (no signed-in user).
  t.modified_at,                                                                -- Audit: when this row was last written. Auto-stamped by the audit trigger (now() on every INSERT/UPDATE).
  t.modified_by,                                                                -- Audit: the JWT user (auth.email()) who last wrote this row. Auto-stamped on every INSERT/UPDATE.
  t.modified_by_model                                                           -- Audit: the AI model credited on the last save when an LLM made/assisted the change (e.g. "gpt-4o"). NULL for plain human writes. Read from the app.modified_by_model session GUC by the audit trigger. The owner (CreatedBy/ModifiedBy) is always the human JWT user, never a model.
FROM roles t;

