-- ----------------------------------------------------------------------------
-- vw_platform_naviation: View for PlatformNaviation
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_platform_naviation CASCADE;
CREATE VIEW vw_platform_naviation WITH (security_invoker = ON) AS
SELECT
  t.platform_naviation_id,
  calc_platform_naviation_name(t.platform_naviation_id) AS name,
  t.display_name,
  t.route,
  t.description,
  t.sort_order,
  t.parent_route_key,                                                           -- Route key of parent nav node (empty for top-level)
  t.route_key,                                                                  -- Stable dot-delimited slug, e.g. checklists.score
  t.nav_level,                                                                  -- Hierarchy level
  t.role_visibility,                                                            -- Comma-separated canonical roles that can see this nav item. Tokens: REP / MANAGER / OPERATIONS / ADMIN (uppercase). ADMIN visibility implies OPERATIONS.
  t.primary_table,                                                              -- Backing table name
  t.erb_package,                                                                -- FK -> ERBPackages.ERBPackageId. The package that owns this route.
  calc_platform_naviation_package_is_active(t.platform_naviation_id) AS package_is_active,-- Lookup: ERBPackage.IsActive — is this route's owning package enabled? UI hides the route when false.
  calc_platform_naviation_package_is_licensed(t.platform_naviation_id) AS package_is_licensed,-- Lookup: ERBPackage.IsLicensed — is this route's owning package licensed? UI hides the route from non-Effortless users when false.
  t.primary_view,                                                               -- Backing vw_* view
  t.business_rule_refs,                                                         -- CSV of rule codes shown on this route
  t.build_phase,                                                                -- Build order phase 1-7
  t.status,                                                                     -- Implementation status
  t.is_licensed,                                                                -- This route's own licensing flag. When false, the route is hidden from non-Effortless users regardless of its package (used to fence off the Effortless Elements admin tooling). Blank/true = licensed.
  t.requires_claim_context,                                                     -- True if route needs an active claim/checklist context
  t.pin_to_top,                                                                 -- Pin this route to the very top of its nav level, before SortOrder
  t.is_dynamic,                                                                 -- True if path contains :params
  t.icon_hint,                                                                  -- Optional icon name for UI
  t.admin_crud,                                                                 -- Admin CRUD grant for this route (contains C/R/U/D). NULL/empty = role cannot access this route. Seeded from RoleVisibility.
  t.manager_crud,                                                               -- Manager CRUD grant for this route (contains C/R/U/D). NULL/empty = role cannot access this route. Seeded from RoleVisibility.
  t.representative_crud,                                                        -- Representative CRUD grant for this route (contains C/R/U/D). NULL/empty = role cannot access this route. Seeded from RoleVisibility.
  t.external_llm_crud,                                                          -- External LLM CRUD grant for this route (contains C/R/U/D). NULL/empty = role cannot access this route. Seeded from RoleVisibility.
  calc_platform_naviation_admin_can_create(t.platform_naviation_id) AS admin_can_create,-- Derived: AdminCRUD contains 'C' (BLANK when AdminCRUD is NULL).
  calc_platform_naviation_admin_can_read(t.platform_naviation_id) AS admin_can_read,-- Derived: AdminCRUD contains 'R' (BLANK when AdminCRUD is NULL).
  calc_platform_naviation_admin_can_update(t.platform_naviation_id) AS admin_can_update,-- Derived: AdminCRUD contains 'U' (BLANK when AdminCRUD is NULL).
  calc_platform_naviation_admin_can_delete(t.platform_naviation_id) AS admin_can_delete,-- Derived: AdminCRUD contains 'D' (BLANK when AdminCRUD is NULL).
  calc_platform_naviation_manager_can_create(t.platform_naviation_id) AS manager_can_create,-- Derived: ManagerCRUD contains 'C' (BLANK when ManagerCRUD is NULL).
  calc_platform_naviation_manager_can_read(t.platform_naviation_id) AS manager_can_read,-- Derived: ManagerCRUD contains 'R' (BLANK when ManagerCRUD is NULL).
  calc_platform_naviation_manager_can_update(t.platform_naviation_id) AS manager_can_update,-- Derived: ManagerCRUD contains 'U' (BLANK when ManagerCRUD is NULL).
  calc_platform_naviation_manager_can_delete(t.platform_naviation_id) AS manager_can_delete,-- Derived: ManagerCRUD contains 'D' (BLANK when ManagerCRUD is NULL).
  calc_platform_naviation_representative_can_create(t.platform_naviation_id) AS representative_can_create,-- Derived: RepresentativeCRUD contains 'C' (BLANK when RepresentativeCRUD is NULL).
  calc_platform_naviation_representative_can_read(t.platform_naviation_id) AS representative_can_read,-- Derived: RepresentativeCRUD contains 'R' (BLANK when RepresentativeCRUD is NULL).
  calc_platform_naviation_representative_can_update(t.platform_naviation_id) AS representative_can_update,-- Derived: RepresentativeCRUD contains 'U' (BLANK when RepresentativeCRUD is NULL).
  calc_platform_naviation_representative_can_delete(t.platform_naviation_id) AS representative_can_delete,-- Derived: RepresentativeCRUD contains 'D' (BLANK when RepresentativeCRUD is NULL).
  calc_platform_naviation_external_llm_can_create(t.platform_naviation_id) AS external_llm_can_create,-- Derived: External LLMCRUD contains 'C' (BLANK when External LLMCRUD is NULL).
  calc_platform_naviation_external_llm_can_read(t.platform_naviation_id) AS external_llm_can_read,-- Derived: External LLMCRUD contains 'R' (BLANK when External LLMCRUD is NULL).
  calc_platform_naviation_external_llm_can_update(t.platform_naviation_id) AS external_llm_can_update,-- Derived: External LLMCRUD contains 'U' (BLANK when External LLMCRUD is NULL).
  calc_platform_naviation_external_llm_can_delete(t.platform_naviation_id) AS external_llm_can_delete,-- Derived: External LLMCRUD contains 'D' (BLANK when External LLMCRUD is NULL).
  calc_platform_naviation_depth(t.platform_naviation_id) AS depth,              -- Calculated — nesting depth in the menu tree. 0 = top-level (no parent); otherwise the number of dot-segments in the dotted RouteKey above the root (e.g. 'library.rules.detail' = 2). Drives N-deep indentation.
  calc_platform_naviation_full_path(t.platform_naviation_id) AS full_path,      -- Calculated — canonical role-agnostic URL path (equals Route). The SPA renders this under each permitted role as /:role + FullPath and resolves it only when that role's *CanRead is true; the role is an implicit prefix, never stored on the row.
  calc_platform_naviation_handler_base_name(t.platform_naviation_id) AS handler_base_name,-- Calculated — space-delimited form of the dotted RouteKey (dots and hyphens become spaces), e.g. 'library rules detail'. The client PascalCases this and prefixes the viewer role to derive the handler component deterministically: {Role} + PascalCase(HandlerBaseName) -> e.g. AdminLibraryRulesDetail, RepresentativeLibraryRulesDetail. No per-role handler is stored; edge cases get their own single-role route row instead.
  t.created_at,                                                                 -- Audit: when this row was first inserted. Auto-stamped by the audit trigger (now() on INSERT); immutable thereafter.
  t.created_by,                                                                 -- Audit: the OWNER — the JWT user (auth.email()) who created this row. Auto-stamped on INSERT; immutable thereafter. NULL for build-time seed rows (no signed-in user).
  t.modified_at,                                                                -- Audit: when this row was last written. Auto-stamped by the audit trigger (now() on every INSERT/UPDATE).
  t.modified_by,                                                                -- Audit: the JWT user (auth.email()) who last wrote this row. Auto-stamped on every INSERT/UPDATE.
  t.modified_by_model                                                           -- Audit: the AI model credited on the last save when an LLM made/assisted the change (e.g. "gpt-4o"). NULL for plain human writes. Read from the app.modified_by_model session GUC by the audit trigger. The owner (CreatedBy/ModifiedBy) is always the human JWT user, never a model.
FROM platform_naviation t;

-- ----------------------------------------------------------------------------
-- vw_jurisdictions: View for Jurisdictions
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_jurisdictions CASCADE;
CREATE VIEW vw_jurisdictions WITH (security_invoker = ON) AS
SELECT
  t.jurisdiction_id,
  calc_jurisdictions_name(t.jurisdiction_id) AS name,
  t.state,
  t.notes,
  t.jurisdiction_type,
  t.code,                                                                       -- Short human code for the jurisdiction, e.g. 'CA-LA', 'NY-NYC', 'TX-AUS'.
  t.display_name,                                                               -- Full readable jurisdiction name, e.g. 'Los Angeles County, California'.
  t.days_to_respond,                                                            -- Number of days after issuance the driver has to respond (pay or request a hearing) before default judgment.
  t.days_to_pay_after_ruling,                                                   -- Number of days after a guilty ruling (or after issuance if not contested) the fine is due before it is late.
  t.late_penalty_pct,                                                           -- Percentage surcharge added to the assessed amount once a payment is late (e.g. 0.25 = 25%).
  t.days_late_to_collections,                                                   -- Number of days a payment may remain late before it is referred to collections.
  t.point_suspension_threshold,                                                 -- Total active license points at or above which a driver's license is suspended in this jurisdiction.
  t.point_warning_threshold,                                                    -- Total active license points at or above which a driver receives an advisory warning (below suspension).
  t.traffic_school_point_cap,                                                   -- Maximum violation points for which traffic school is offered as a points-reducing option in this jurisdiction.
  t.parent_jurisdiction,                                                        -- The parent jurisdiction in the hierarchy (e.g., US for California). Empty for root jurisdictions like countries.
  calc_jurisdictions_parent_jurisdiction_name(t.jurisdiction_id) AS parent_jurisdiction_name,
  t.child_jurisdictions,                                                        -- The child jurisdictions under this parent (e.g., all 50 states roll up to US).
  t.jurisdiction_rules,
  calc_jurisdictions_is_root_jurisdiction(t.jurisdiction_id) AS is_root_jurisdiction,
  calc_jurisdictions_child_jurisdiction_count(t.jurisdiction_id) AS child_jurisdiction_count,
  calc_jurisdictions_relative_path(t.jurisdiction_id) AS relative_path,         -- Concrete relative URL for this jurisdiction's explorer/detail page. Self-contained (no route-table lookup) so it is always populated. Anywhere a jurisdiction is referenced, link to this path.
  calc_jurisdictions_rule_count(t.jurisdiction_id) AS rule_count,               -- How many JurisdictionRules belong to this jurisdiction (drives the explorer badges).
  t.source_documents,                                                           -- Source documents (e.g. Appeal Board Decision PDFs) downloaded for this jurisdiction; rules are extracted from them.
  calc_jurisdictions_source_document_count(t.jurisdiction_id) AS source_document_count,
