-- ----------------------------------------------------------------------------
-- vw_jurisdiction_rules: View for JurisdictionRules
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_jurisdiction_rules CASCADE;
CREATE VIEW vw_jurisdiction_rules WITH (security_invoker = ON) AS
SELECT
  t.jurisdiction_rule_id,
  calc_jurisdiction_rules_name(t.jurisdiction_rule_id) AS name,
  t.route,                                                                      -- Platform route this JurisdictionRules row navigates to. Defaults to the "rule-detail" detail route; its template feeds RelativePath.
  calc_jurisdiction_rules_route_path(t.jurisdiction_rule_id) AS route_path,     -- The route template (with :params) pulled from the linked PlatformNaviation route.
  calc_jurisdiction_rules_relative_path(t.jurisdiction_rule_id) AS relative_path,-- Concrete relative URL for this rule's detail page. Self-contained (dedicated /library/jurisdiction-rules/ space) so it never collides with the business-rule library at /library/rules. Anywhere a jurisdiction rule is referenced, link to this path.
  t.rule_number,
  t.title,
  t.description,
  t.category,
  t.effective_date,
  t.citation_url,
  t.ai_version,                                                                 -- The AI-distilled 'traffic-ticket-contest version' of this rule: a compact, plain-language restatement of exactly what this rule means for an unemployment claim. This is the context injected when the rule is invoked, so only this (not the full statute / source PDF) need be included in a claim's prompt.
  t.ai_version_updated_at,                                                      -- When AiVersion was last generated or approved.
  t.ai_version_model,                                                           -- Provenance: the model / author that produced the current AiVersion (e.g. a model slug, or 'human').
  t.source_document,                                                            -- The source document (e.g. Appeal Board Decision PDF) this rule was extracted from.
  t.jurisdiction,
  calc_jurisdiction_rules_jurisdiction_name(t.jurisdiction_rule_id) AS jurisdiction_name,
  calc_jurisdiction_rules_jurisdiction_type(t.jurisdiction_rule_id) AS jurisdiction_type,
  calc_jurisdiction_rules_is_federal(t.jurisdiction_rule_id) AS is_federal,
  t.created_at,                                                                 -- Audit: when this row was first inserted. Auto-stamped by the audit trigger (now() on INSERT); immutable thereafter.
  t.created_by,                                                                 -- Audit: the OWNER — the JWT user (auth.email()) who created this row. Auto-stamped on INSERT; immutable thereafter. NULL for build-time seed rows (no signed-in user).
  t.modified_at,                                                                -- Audit: when this row was last written. Auto-stamped by the audit trigger (now() on every INSERT/UPDATE).
  t.modified_by,                                                                -- Audit: the JWT user (auth.email()) who last wrote this row. Auto-stamped on every INSERT/UPDATE.
  t.modified_by_model                                                           -- Audit: the AI model credited on the last save when an LLM made/assisted the change (e.g. "gpt-4o"). NULL for plain human writes. Read from the app.modified_by_model session GUC by the audit trigger. The owner (CreatedBy/ModifiedBy) is always the human JWT user, never a model.
FROM jurisdiction_rules t;

