DROP VIEW IF EXISTS vw_state_transition_rules CASCADE;
CREATE VIEW vw_state_transition_rules WITH (security_invoker = ON) AS
SELECT
  t.state_transition_rule_id,                                                   -- Slug PK, e.g. 'checklist-draft-to-in_progress'.
  calc_state_transition_rules_name(t.state_transition_rule_id) AS name,         -- Echoes StateTransitionRuleId.
  t.state_machine,                                                              -- FK -> StateMachines.StateMachineId.
  t.from_state,                                                                 -- FK -> MachineStates.MachineStateId.
  t.to_state,                                                                   -- FK -> MachineStates.MachineStateId.
  t.guard_description,                                                          -- Prose guard citing existing R-codes (e.g. 'R4: requires SeparationType + PrimaryAllegation'). Does NOT reimplement rule logic.
  t.rule_refs,                                                                  -- CSV of BusinessRule codes the guard enforces.
  t.trigger_endpoint,                                                           -- APIEndpoints id whose action fires this transition.
  t.triggered_by_role,                                                          -- Role that fires this edge. Enum: REP / MANAGER / CLIENT / state-agency / ocr-job / ai-step / EY_BATCH / SYSTEM.
  calc_state_transition_rules_from_state_key(t.state_transition_rule_id) AS from_state_key,-- Lookup: FromState.StateKey.
  calc_state_transition_rules_to_state_key(t.state_transition_rule_id) AS to_state_key,-- Lookup: ToState.StateKey.
  calc_state_transition_rules_is_forward_edge(t.state_transition_rule_id) AS is_forward_edge,-- TRUE when ToState is not the machine's initial state.
  t.created_at,                                                                 -- Audit: when this row was first inserted. Auto-stamped by the audit trigger (now() on INSERT); immutable thereafter.
  t.created_by,                                                                 -- Audit: the OWNER — the JWT user (auth.email()) who created this row. Auto-stamped on INSERT; immutable thereafter. NULL for build-time seed rows (no signed-in user).
