FROM state_transition_rules t;

-- ----------------------------------------------------------------------------
-- vw_state_transitions: View for StateTransitions
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_state_transitions CASCADE;
CREATE VIEW vw_state_transitions WITH (security_invoker = ON) AS
SELECT
  t.state_transition_id,                                                        -- Slug PK.
  calc_state_transitions_name(t.state_transition_id) AS name,                   -- Echoes StateTransitionId.
  t.state_machine,                                                              -- FK -> StateMachines.StateMachineId.
  t.subject_table_name,                                                         -- Polymorphic pointer: name of the subject's table (raw string, NOT a relationship).
  t.subject_id,                                                                 -- Polymorphic pointer: id of the subject row (raw string, NOT a relationship).
  t.from_state_key,                                                             -- Bare from-state value (mirror of today's FromStage). Null on the initial creation transition.
  t.to_state_key,                                                               -- Bare to-state value (mirror of today's ToStage).
  t.transition_at,                                                              -- When the transition occurred.
  t.triggered_by,                                                               -- FK -> AppUsers.AppUserId — the actor when a human. Null for system/automated transitions.
  t.triggered_by_role,                                                          -- Role that fired this transition. Enum: REP / MANAGER / CLIENT / state-agency / ocr-job / ai-step / EY_BATCH / SYSTEM.
  t.reason,                                                                     -- Why the transition happened (free text; carries old Notes/Reason).
  calc_state_transitions_is_forward(t.state_transition_id) AS is_forward,       -- Generalizes the old =NOT(ToStage="DRAFT"): TRUE when ToStateKey is not the machine's initial state.
  t.created_at,                                                                 -- Audit: when this row was first inserted. Auto-stamped by the audit trigger (now() on INSERT); immutable thereafter.
  t.created_by,                                                                 -- Audit: the OWNER — the JWT user (auth.email()) who created this row. Auto-stamped on INSERT; immutable thereafter. NULL for build-time seed rows (no signed-in user).
  t.modified_at,                                                                -- Audit: when this row was last written. Auto-stamped by the audit trigger (now() on every INSERT/UPDATE).
  t.modified_by,                                                                -- Audit: the JWT user (auth.email()) who last wrote this row. Auto-stamped on every INSERT/UPDATE.
  t.modified_by_model                                                           -- Audit: the AI model credited on the last save when an LLM made/assisted the change (e.g. "gpt-4o"). NULL for plain human writes. Read from the app.modified_by_model session GUC by the audit trigger. The owner (CreatedBy/ModifiedBy) is always the human JWT user, never a model.
FROM state_transitions t;

