-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_work_queue_items CASCADE;
CREATE VIEW vw_work_queue_items WITH (security_invoker = ON) AS
SELECT
  t.work_queue_item_id,                                                         -- Slug PK: subject-table + subject-id.
  calc_work_queue_items_name(t.work_queue_item_id) AS name,                     -- Echoes WorkQueueItemId.
  t.subject_table_name,                                                         -- Polymorphic pointer: subject's table name (raw string, NOT a relationship).
  t.subject_id,                                                                 -- Polymorphic pointer: subject row id (raw string, NOT a relationship).
  t.item_type,                                                                  -- What kind of work this is. Enum: sides-response / benefit-charge / DETERMINATION / document-ocr / CHECKLIST / hearing-prep.
  t.current_state_key,                                                          -- Current (non-terminal) state of the subject, copied from its state column.
  t.due_date,                                                                   -- Due date carried from the subject (e.g. Citations.PaymentDueDate, Citations.ResponseDueDate).
  calc_work_queue_items_due_in_days(t.work_queue_item_id) AS due_in_days,       -- Calculated — days until DueDate (negative when overdue).
  t.assigned_to,                                                                -- FK -> AppUsers.AppUserId — the AppUser who owns this work item.
  calc_work_queue_items_is_overdue(t.work_queue_item_id) AS is_overdue,         -- TRUE when DueInDays < 0.
  calc_work_queue_items_urgency_bucket(t.work_queue_item_id) AS urgency_bucket, -- URGENT (overdue or due today) / DUE_3_DAYS / UPCOMING / FOLLOW_UP (no due date).
  calc_work_queue_items_is_urgent(t.work_queue_item_id) AS is_urgent,           -- TRUE when UrgencyBucket = URGENT.
  t.created_at,                                                                 -- Audit: when this row was first inserted. Auto-stamped by the audit trigger (now() on INSERT); immutable thereafter.
  t.created_by,                                                                 -- Audit: the OWNER — the JWT user (auth.email()) who created this row. Auto-stamped on INSERT; immutable thereafter. NULL for build-time seed rows (no signed-in user).
  t.modified_at,                                                                -- Audit: when this row was last written. Auto-stamped by the audit trigger (now() on every INSERT/UPDATE).
  t.modified_by,                                                                -- Audit: the JWT user (auth.email()) who last wrote this row. Auto-stamped on every INSERT/UPDATE.
  t.modified_by_model                                                           -- Audit: the AI model credited on the last save when an LLM made/assisted the change (e.g. "gpt-4o"). NULL for plain human writes. Read from the app.modified_by_model session GUC by the audit trigger. The owner (CreatedBy/ModifiedBy) is always the human JWT user, never a model.
FROM work_queue_items t;

-- ----------------------------------------------------------------------------
-- vw_ai_models: View for AiModels
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_ai_models CASCADE;
CREATE VIEW vw_ai_models WITH (security_invoker = ON) AS
SELECT
  t.ai_model_id,                                                                -- Slug PK, e.g. 'gpt-4o-mini', 'erb-internal-classifier'.
  calc_ai_models_name(t.ai_model_id) AS name,                                   -- Echoes AiModelId.
  t.title,                                                                      -- Human-readable model name.
  t.provider,                                                                   -- Provider/vendor key (lower-kebab): openai / anthropic / google / erb-internal.
  t.description,                                                                -- What the model is and when the assistant uses it.
  t.is_internal,                                                                -- TRUE for ERB-owned/self-hosted models (vs a third-party API).
  t.is_active,                                                                  -- Whether this model is currently selectable by the assistant.
  t.context_window_tokens,                                                      -- Max context window in tokens (reference only).
  calc_ai_models_model_pricing_versions(t.ai_model_id) AS model_pricing_versions,-- Reverse: pricing versions for this model.
  calc_ai_models_assistant_turns(t.ai_model_id) AS assistant_turns,             -- Reverse: assistant turns served by this model.
  calc_ai_models_pricing_version_count(t.ai_model_id) AS pricing_version_count, -- Count of pricing versions on this model.
  calc_ai_models_turn_count(t.ai_model_id) AS turn_count,                       -- Count of assistant turns served by this model.
  calc_ai_models_total_cost(t.ai_model_id) AS total_cost,                       -- Rollup — total USD spend across all turns served by this model.
  t.created_at,                                                                 -- Audit: when this row was first inserted. Auto-stamped by the audit trigger (now() on INSERT); immutable thereafter.
  t.created_by,                                                                 -- Audit: the OWNER — the JWT user (auth.email()) who created this row. Auto-stamped on INSERT; immutable thereafter. NULL for build-time seed rows (no signed-in user).
  t.modified_at,                                                                -- Audit: when this row was last written. Auto-stamped by the audit trigger (now() on every INSERT/UPDATE).
  t.modified_by,                                                                -- Audit: the JWT user (auth.email()) who last wrote this row. Auto-stamped on every INSERT/UPDATE.
  t.modified_by_model                                                           -- Audit: the AI model credited on the last save when an LLM made/assisted the change (e.g. "gpt-4o"). NULL for plain human writes. Read from the app.modified_by_model session GUC by the audit trigger. The owner (CreatedBy/ModifiedBy) is always the human JWT user, never a model.
FROM ai_models t;

-- ----------------------------------------------------------------------------
-- vw_model_pricing_versions: View for ModelPricingVersions
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_model_pricing_versions CASCADE;
CREATE VIEW vw_model_pricing_versions WITH (security_invoker = ON) AS
SELECT
  t.model_pricing_version_id,                                                   -- Slug PK, e.g. 'gpt-4o-mini-2025-07'.
  calc_model_pricing_versions_name(t.model_pricing_version_id) AS name,         -- Echoes ModelPricingVersionId.
  t.ai_model,                                                                   -- FK -> AiModels.AiModelId.
  t.label,                                                                      -- Human-readable label for this pricing era.
  t.currency,                                                                   -- ISO currency code (lower-kebab), e.g. 'usd'.
  t.input_price_per_m_tok,                                                      -- Price per 1,000,000 NON-cached input tokens.
  t.cached_input_price_per_m_tok,                                               -- Price per 1,000,000 cached input tokens (prompt-cache reads). 0 if unsupported.
  t.output_price_per_m_tok,                                                     -- Price per 1,000,000 output (completion) tokens.
  t.effective_date,                                                             -- Date this pricing took effect (date-only business date).
  t.is_active,                                                                  -- TRUE for the currently-billing version of this model; superseded versions are FALSE.
  t.notes,                                                                      -- Free text — source/announcement of this pricing.
  calc_model_pricing_versions_ai_model_title(t.model_pricing_version_id) AS ai_model_title,-- Lookup: AiModel.Title.
  calc_model_pricing_versions_assistant_turns(t.model_pricing_version_id) AS assistant_turns,-- Reverse: assistant turns priced with this version.
  calc_model_pricing_versions_turn_count(t.model_pricing_version_id) AS turn_count,-- Count of assistant turns priced with this version.
  t.created_at,                                                                 -- Audit: when this row was first inserted. Auto-stamped by the audit trigger (now() on INSERT); immutable thereafter.
  t.created_by,                                                                 -- Audit: the OWNER — the JWT user (auth.email()) who created this row. Auto-stamped on INSERT; immutable thereafter. NULL for build-time seed rows (no signed-in user).
  t.modified_at,                                                                -- Audit: when this row was last written. Auto-stamped by the audit trigger (now() on every INSERT/UPDATE).
  t.modified_by,                                                                -- Audit: the JWT user (auth.email()) who last wrote this row. Auto-stamped on every INSERT/UPDATE.
  t.modified_by_model                                                           -- Audit: the AI model credited on the last save when an LLM made/assisted the change (e.g. "gpt-4o"). NULL for plain human writes. Read from the app.modified_by_model session GUC by the audit trigger. The owner (CreatedBy/ModifiedBy) is always the human JWT user, never a model.
FROM model_pricing_versions t;

-- ----------------------------------------------------------------------------
-- vw_assistant_turns: View for AssistantTurns
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_assistant_turns CASCADE;
CREATE VIEW vw_assistant_turns WITH (security_invoker = ON) AS
SELECT
  t.assistant_turn_id,                                                          -- Slug/uuid PK for the turn.
  calc_assistant_turns_name(t.assistant_turn_id) AS name,                       -- Echoes AssistantTurnId.
  t.created_at,                                                                 -- When the turn was submitted (ISO timestamp).
  t.current_state_key,                                                          -- Final state of the chat-agent machine for this turn: 'responding' (success) or 'failed'. Bare StateKey value.
  t.question_kind,                                                              -- Classifier branch: rulebook / company / claim.
  t.route_path,                                                                 -- Concrete app path the turn was active on, e.g. '/claims/zamora-thiago-2026-01-30'.
  t.route_key,                                                                  -- PlatformNaviation route_key in scope when known (raw string, not an FK — concrete instance paths need not match a nav row).
  t.citation,                                                                   -- FK to the Citation this assistant turn concerns.
  t.app_user_id,                                                                -- App user who asked (raw id; linked logically).
  t.ai_model,                                                                   -- FK -> AiModels.AiModelId — model that answered.
  t.model_pricing_version,                                                      -- FK -> ModelPricingVersions.ModelPricingVersionId — the exact pricing version used to bill this turn (snapshotted so historical cost is stable even after prices change).
  t.user_message,                                                               -- The user's question text for this turn.
  t.assistant_reply,                                                            -- The assistant's reply text.
  t.raw_exchange,                                                               -- Full request/response metadata as raw JSON (messages, system-prompt kind, usage block, finish reason, latency).
  t.input_tokens,                                                               -- Total prompt/input tokens (including any cached).
  t.cached_input_tokens,                                                        -- Portion of input tokens served from prompt cache (billed at the cached rate).
  t.output_tokens,                                                              -- Completion/output tokens.
  calc_assistant_turns_total_tokens(t.assistant_turn_id) AS total_tokens,       -- Input + output tokens.
  calc_assistant_turns_billable_input_tokens(t.assistant_turn_id) AS billable_input_tokens,-- Non-cached input tokens = InputTokens - CachedInputTokens.
  calc_assistant_turns_ai_model_title(t.assistant_turn_id) AS ai_model_title,   -- Lookup: AiModel.Title.
  calc_assistant_turns_input_price_per_m_tok(t.assistant_turn_id) AS input_price_per_m_tok,-- Lookup: ModelPricingVersion.InputPricePerMTok.
  calc_assistant_turns_cached_input_price_per_m_tok(t.assistant_turn_id) AS cached_input_price_per_m_tok,-- Lookup: ModelPricingVersion.CachedInputPricePerMTok.
  calc_assistant_turns_output_price_per_m_tok(t.assistant_turn_id) AS output_price_per_m_tok,-- Lookup: ModelPricingVersion.OutputPricePerMTok.
  calc_assistant_turns_input_cost(t.assistant_turn_id) AS input_cost,           -- USD cost of input: (BillableInputTokens × InputPrice + CachedInputTokens × CachedInputPrice) / 1,000,000.
  calc_assistant_turns_output_cost(t.assistant_turn_id) AS output_cost,         -- USD cost of output: OutputTokens × OutputPrice / 1,000,000.
  calc_assistant_turns_total_cost(t.assistant_turn_id) AS total_cost,           -- Total USD cost for this turn = InputCost + OutputCost. Rolls up to Client and Claim.
  t.created_by,                                                                 -- Audit: the OWNER — the JWT user (auth.email()) who created this row. Auto-stamped on INSERT; immutable thereafter. NULL for build-time seed rows (no signed-in user).
  t.modified_at,                                                                -- Audit: when this row was last written. Auto-stamped by the audit trigger (now() on every INSERT/UPDATE).
  t.modified_by,                                                                -- Audit: the JWT user (auth.email()) who last wrote this row. Auto-stamped on every INSERT/UPDATE.
  t.modified_by_model                                                           -- Audit: the AI model credited on the last save when an LLM made/assisted the change (e.g. "gpt-4o"). NULL for plain human writes. Read from the app.modified_by_model session GUC by the audit trigger. The owner (CreatedBy/ModifiedBy) is always the human JWT user, never a model.
FROM assistant_turns t;

