-- ----------------------------------------------------------------------------
-- vw_erb_packages: View for ERBPackages
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_erb_packages CASCADE;
CREATE VIEW vw_erb_packages WITH (security_invoker = ON) AS
SELECT
  t.erb_package_id,                                                             -- PK — kebab logical key for the package.
  calc_erb_packages_name(t.erb_package_id) AS name,                             -- Echoes ERBPackageId.
  t.title,                                                                      -- Human-readable package name.
  t.description,                                                                -- What this package/product module does, in prose.
  t.status,                                                                     -- Lifecycle: SHIPPED / in-progress / PLANNED / DEPRECATED.
  t.is_active,                                                                  -- Master switch. When false, every table/field/route owned by this package reports PackageIsActive=false and the UI hides it pervasively (rows stay in the DB).
  t.is_licensed,                                                                -- Licensing master switch. When false, every route owned by this package reports PackageIsLicensed=false and is hidden from non-Effortless users (rows stay in the DB; Effortless staff still see them). Separate axis from IsActive.
  t.sort_order,                                                                 -- Display order in a generated spec / nav.
  t.is_key,                                                                     -- Star flag — marks the headline packages so users can focus on the top platform capabilities amid the long tail. Blank/false = ordinary packages.
  t.source_text,                                                                -- Supporting/original source text (markdown) describing the package.
  t.source_files,                                                               -- Comma-separated repo-relative path(s) of the source document(s).
  t.erb_features,                                                               -- Reverse link to ERBFeatures — child feature rows belonging to this package (1->many).
  calc_erb_packages_erb_tables(t.erb_package_id) AS erb_tables,                 -- Reverse link to ERBTables — tables belonging to this package (1->many).
  calc_erb_packages_platform_naviation(t.erb_package_id) AS platform_naviation, -- Reverse link to PlatformNaviation — routes belonging to this package (1->many).
  calc_erb_packages_state_machines(t.erb_package_id) AS state_machines,         -- Reverse link to StateMachines — state machines belonging to this package (1->many).
  calc_erb_packages_feature_count(t.erb_package_id) AS feature_count,           -- Count of child ERBFeatures rows.
  calc_erb_packages_shipped_feature_count(t.erb_package_id) AS shipped_feature_count,-- Count of child features with Status = SHIPPED.
  t.created_at,                                                                 -- Audit: when this row was first inserted. Auto-stamped by the audit trigger (now() on INSERT); immutable thereafter.
  t.created_by,                                                                 -- Audit: the OWNER — the JWT user (auth.email()) who created this row. Auto-stamped on INSERT; immutable thereafter. NULL for build-time seed rows (no signed-in user).
  t.modified_at,                                                                -- Audit: when this row was last written. Auto-stamped by the audit trigger (now() on every INSERT/UPDATE).
  t.modified_by,                                                                -- Audit: the JWT user (auth.email()) who last wrote this row. Auto-stamped on every INSERT/UPDATE.
  t.modified_by_model                                                           -- Audit: the AI model credited on the last save when an LLM made/assisted the change (e.g. "gpt-4o"). NULL for plain human writes. Read from the app.modified_by_model session GUC by the audit trigger. The owner (CreatedBy/ModifiedBy) is always the human JWT user, never a model.
FROM erb_packages t;

