CREATE VIEW vw_erb_feature_statuses WITH (security_invoker = ON) AS
SELECT
  t.erb_feature_status_id,                                                      -- PK = status key (DESIGNED / PLANNED / in-progress / SHIPPED / DEFERRED).
  calc_erb_feature_statuses_name(t.erb_feature_status_id) AS name,              -- Echoes ERBFeatureStatusId.
  t.title,                                                                      -- Human-readable status title.
