  calc_erb_feature_categories_erb_features(t.erb_feature_category_id) AS erb_features,-- Reverse: features in this category.
  calc_erb_feature_categories_feature_count(t.erb_feature_category_id) AS feature_count,-- Count of ERBFeatures in this category.
