-- ----------------------------------------------------------------------------
-- vw_erb_features: View for ERBFeatures
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_erb_features CASCADE;
CREATE VIEW vw_erb_features WITH (security_invoker = ON) AS
SELECT
  t.erb_feature_id,                                                             -- PK — kebab logical key for the feature.
  calc_erb_features_name(t.erb_feature_id) AS name,                             -- Echoes ERBFeatureId.
  t.route,                                                                      -- Platform route this ERBFeatures row navigates to. Defaults to the "feature-detail" detail route; its template feeds RelativePath.
  calc_erb_features_route_path(t.erb_feature_id) AS route_path,                 -- The route template (with :params) pulled from the linked PlatformNaviation route.
  calc_erb_features_relative_path(t.erb_feature_id) AS relative_path,           -- Concrete relative URL for this row — the route template with its :param(s) substituted by this row's own id(s).
  t.erb_package,                                                                -- FK -> ERBPackages.ERBPackageId. The package this feature belongs to (many features -> one package).
  t.is_licensed,                                                                -- This feature's own licensing flag. When false, the feature is hidden from non-Effortless users regardless of its package (used to fence off Effortless Elements tooling features). Blank/true = licensed.
  calc_erb_features_package_is_licensed(t.erb_feature_id) AS package_is_licensed,-- Lookup: ERBPackage.IsLicensed — is this feature's owning package licensed? UI hides the feature from non-Effortless users when false.
  t.title,                                                                      -- Human-readable feature name.
  t.description,                                                                -- What the feature does, in prose.
  t.category,                                                                   -- FK to ERBFeatureCategories — the cross-package functional category this feature belongs to (intake / scoring / module / validation / review / output / extraction / prep / dashboard / integration / data-model / platform / devops).
  calc_erb_features_category_title(t.erb_feature_id) AS category_title,         -- Lookup: Category.Title — human-readable category name.
  t.status,                                                                     -- FK to ERBFeatureStatuses — feature lifecycle status.
  calc_erb_features_status_title(t.erb_feature_id) AS status_title,             -- Lookup: Status.Title.
  calc_erb_features_status_description(t.erb_feature_id) AS status_description, -- Lookup: Status.Description.
  calc_erb_features_status_is_active(t.erb_feature_id) AS status_is_active,     -- Lookup: Status.IsActive — whether this feature is part of the official shared view.
  t.sort_order,                                                                 -- Display order within the package.
  t.is_key,                                                                     -- Star flag — marks the headline features so users can focus on the top platform capabilities amid the long tail. Blank/false = ordinary features.
  t.rule_refs,                                                                  -- Comma-separated BusinessRules.RuleCode refs (R1..R38) this feature implements, if any.
  t.source_text,                                                                -- Original / supporting source text (markdown) that describes this feature.
  t.source_files,                                                               -- Comma-separated repo-relative path(s) of the source document(s).
  t.image_url,                                                                  -- Repo-relative path to a cartoon illustration of this feature (generated, 300x300 PNG under assets/feature-images/).
  t.created_at,                                                                 -- Audit: when this row was first inserted. Auto-stamped by the audit trigger (now() on INSERT); immutable thereafter.
  t.created_by,                                                                 -- Audit: the OWNER — the JWT user (auth.email()) who created this row. Auto-stamped on INSERT; immutable thereafter. NULL for build-time seed rows (no signed-in user).
  t.modified_at,                                                                -- Audit: when this row was last written. Auto-stamped by the audit trigger (now() on every INSERT/UPDATE).
  t.modified_by,                                                                -- Audit: the JWT user (auth.email()) who last wrote this row. Auto-stamped on every INSERT/UPDATE.
  t.modified_by_model                                                           -- Audit: the AI model credited on the last save when an LLM made/assisted the change (e.g. "gpt-4o"). NULL for plain human writes. Read from the app.modified_by_model session GUC by the audit trigger. The owner (CreatedBy/ModifiedBy) is always the human JWT user, never a model.
FROM erb_features t;

-- ----------------------------------------------------------------------------
-- vw_erb_tables: View for ERBTables
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_erb_tables CASCADE;
CREATE VIEW vw_erb_tables WITH (security_invoker = ON) AS
SELECT
  t.erb_table_id,                                                               -- PK = the table name as it appears in the rulebook.
  calc_erb_tables_name(t.erb_table_id) AS name,                                 -- Echoes ERBTableId.
  t.table_name,                                                                 -- Table name.
  t.description,                                                                -- Table description (copied from the rulebook; refreshed additively by build).
  t.erb_package,                                                                -- FK -> ERBPackages.ERBPackageId. The package that owns this table.
  t.platform,                                                                   -- FK -> Platforms.PlatformId. The platform this table belongs to.
  calc_erb_tables_package_is_active(t.erb_table_id) AS package_is_active,       -- Lookup: ERBPackage.IsActive — is this table's owning package enabled?
  t.is_licensed,                                                                -- This table's own licensing flag. When false, the table is hidden from non-Effortless users regardless of its package (used to fence off Effortless Elements meta/catalog tables). Blank/true = licensed.
  calc_erb_tables_package_is_licensed(t.erb_table_id) AS package_is_licensed,   -- Lookup: ERBPackage.IsLicensed — is this table's owning package licensed? UI hides the table from non-Effortless users when false.
  t.field_count,                                                                -- Number of fields (refreshed by build).
  t.is_catalog,                                                                 -- TRUE for the meta/catalog tables themselves.
  t.admin_crud,                                                                 -- Admin CRUD grant for this table (contains C/R/U/D). NULL inherits Roles.DefaultCRUD for Admin.
  t.admin_where,                                                                -- Admin row-access policy (SQL WHERE fragment) limiting which rows of this table Admin may see. NULL = no row restriction. Source for the RLS plan.
  t.manager_crud,                                                               -- Manager CRUD grant for this table (contains C/R/U/D). NULL inherits Roles.DefaultCRUD for Manager.
  t.manager_where,                                                              -- Manager row-access policy (SQL WHERE fragment) limiting which rows of this table Manager may see. NULL = no row restriction. Source for the RLS plan.
  t.representative_crud,                                                        -- Representative CRUD grant for this table (contains C/R/U/D). NULL inherits Roles.DefaultCRUD for Representative.
  t.representative_where,                                                       -- Representative row-access policy (SQL WHERE fragment) limiting which rows of this table Representative may see. NULL = no row restriction. Source for the RLS plan.
  t.external_llm_crud,                                                          -- External LLM CRUD grant for this table (contains C/R/U/D). NULL inherits Roles.DefaultCRUD for External LLM.
  t.external_llm_where,                                                         -- External LLM row-access policy (SQL WHERE fragment) limiting which rows of this table External LLM may see. NULL = no row restriction. Source for the RLS plan.
  calc_erb_tables_admin_can_create(t.erb_table_id) AS admin_can_create,         -- Derived: AdminCRUD contains 'C' (BLANK when AdminCRUD is NULL = inherits role default).
  calc_erb_tables_admin_can_read(t.erb_table_id) AS admin_can_read,             -- Derived: AdminCRUD contains 'R' (BLANK when AdminCRUD is NULL = inherits role default).
  calc_erb_tables_admin_can_update(t.erb_table_id) AS admin_can_update,         -- Derived: AdminCRUD contains 'U' (BLANK when AdminCRUD is NULL = inherits role default).
  calc_erb_tables_admin_can_delete(t.erb_table_id) AS admin_can_delete,         -- Derived: AdminCRUD contains 'D' (BLANK when AdminCRUD is NULL = inherits role default).
  calc_erb_tables_manager_can_create(t.erb_table_id) AS manager_can_create,     -- Derived: ManagerCRUD contains 'C' (BLANK when ManagerCRUD is NULL = inherits role default).
  calc_erb_tables_manager_can_read(t.erb_table_id) AS manager_can_read,         -- Derived: ManagerCRUD contains 'R' (BLANK when ManagerCRUD is NULL = inherits role default).
  calc_erb_tables_manager_can_update(t.erb_table_id) AS manager_can_update,     -- Derived: ManagerCRUD contains 'U' (BLANK when ManagerCRUD is NULL = inherits role default).
  calc_erb_tables_manager_can_delete(t.erb_table_id) AS manager_can_delete,     -- Derived: ManagerCRUD contains 'D' (BLANK when ManagerCRUD is NULL = inherits role default).
  calc_erb_tables_representative_can_create(t.erb_table_id) AS representative_can_create,-- Derived: RepresentativeCRUD contains 'C' (BLANK when RepresentativeCRUD is NULL = inherits role default).
  calc_erb_tables_representative_can_read(t.erb_table_id) AS representative_can_read,-- Derived: RepresentativeCRUD contains 'R' (BLANK when RepresentativeCRUD is NULL = inherits role default).
  calc_erb_tables_representative_can_update(t.erb_table_id) AS representative_can_update,-- Derived: RepresentativeCRUD contains 'U' (BLANK when RepresentativeCRUD is NULL = inherits role default).
  calc_erb_tables_representative_can_delete(t.erb_table_id) AS representative_can_delete,-- Derived: RepresentativeCRUD contains 'D' (BLANK when RepresentativeCRUD is NULL = inherits role default).
  calc_erb_tables_external_llm_can_create(t.erb_table_id) AS external_llm_can_create,-- Derived: External LLMCRUD contains 'C' (BLANK when External LLMCRUD is NULL = inherits role default).
  calc_erb_tables_external_llm_can_read(t.erb_table_id) AS external_llm_can_read,-- Derived: External LLMCRUD contains 'R' (BLANK when External LLMCRUD is NULL = inherits role default).
  calc_erb_tables_external_llm_can_update(t.erb_table_id) AS external_llm_can_update,-- Derived: External LLMCRUD contains 'U' (BLANK when External LLMCRUD is NULL = inherits role default).
  calc_erb_tables_external_llm_can_delete(t.erb_table_id) AS external_llm_can_delete,-- Derived: External LLMCRUD contains 'D' (BLANK when External LLMCRUD is NULL = inherits role default).
  t.admin_is_redacted,                                                          -- Per-table redaction override for Admin. NULL = inherit Roles.IsRedactedRole. TRUE/FALSE explicitly sets whether this role is redacted FOR THIS TABLE (drives the default field access on "<Field>Redacted"-paired fields).
  t.manager_is_redacted,                                                        -- Per-table redaction override for Manager. NULL = inherit Roles.IsRedactedRole. TRUE/FALSE explicitly sets whether this role is redacted FOR THIS TABLE (drives the default field access on "<Field>Redacted"-paired fields).
  t.representative_is_redacted,                                                 -- Per-table redaction override for Representative. NULL = inherit Roles.IsRedactedRole. TRUE/FALSE explicitly sets whether this role is redacted FOR THIS TABLE (drives the default field access on "<Field>Redacted"-paired fields).
  t.external_llm_is_redacted,                                                   -- Per-table redaction override for External LLM. NULL = inherit Roles.IsRedactedRole. TRUE/FALSE explicitly sets whether this role is redacted FOR THIS TABLE (drives the default field access on "<Field>Redacted"-paired fields).
  calc_erb_tables_erb_fields(t.erb_table_id) AS erb_fields,                     -- Reverse: fields belonging to this table.
  t.created_at,                                                                 -- Audit: when this row was first inserted. Auto-stamped by the audit trigger (now() on INSERT); immutable thereafter.
  t.created_by,                                                                 -- Audit: the OWNER — the JWT user (auth.email()) who created this row. Auto-stamped on INSERT; immutable thereafter. NULL for build-time seed rows (no signed-in user).
  t.modified_at,                                                                -- Audit: when this row was last written. Auto-stamped by the audit trigger (now() on every INSERT/UPDATE).
  t.modified_by,                                                                -- Audit: the JWT user (auth.email()) who last wrote this row. Auto-stamped on every INSERT/UPDATE.
  t.modified_by_model                                                           -- Audit: the AI model credited on the last save when an LLM made/assisted the change (e.g. "gpt-4o"). NULL for plain human writes. Read from the app.modified_by_model session GUC by the audit trigger. The owner (CreatedBy/ModifiedBy) is always the human JWT user, never a model.
FROM erb_tables t;

-- ----------------------------------------------------------------------------
-- vw_erb_fields: View for ERBFields
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_erb_fields CASCADE;
CREATE VIEW vw_erb_fields WITH (security_invoker = ON) AS
SELECT
  t.erb_field_id,                                                               -- PK = TableName.FieldName.
  calc_erb_fields_name(t.erb_field_id) AS name,                                 -- Echoes ERBFieldId.
  t.erb_table,                                                                  -- FK to ERBTables — the field's table.
  calc_erb_fields_table_package_is_active(t.erb_field_id) AS table_package_is_active,-- Lookup: ERBTable.PackageIsActive — is the package owning this field's table enabled? (field inherits its table's package).
  t.field_name,                                                                 -- Field name.
  t.field_type,                                                                 -- raw / calculated / lookup / relationship / aggregation.
  t.datatype,                                                                   -- Field datatype.
  t.description,                                                                -- Field description (refreshed additively by build).
  calc_erb_fields_is_calculated(t.erb_field_id) AS is_calculated,               -- TRUE for calculated/lookup/aggregation (read-only at the data layer).
  t.admin_crud,                                                                 -- Admin CRUD grant for this field (contains C/R/U/D). NULL inherits ERBTables.AdminCRUD.
  t.manager_crud,                                                               -- Manager CRUD grant for this field (contains C/R/U/D). NULL inherits ERBTables.ManagerCRUD.
  t.representative_crud,                                                        -- Representative CRUD grant for this field (contains C/R/U/D). NULL inherits ERBTables.RepresentativeCRUD.
  t.external_llm_crud,                                                          -- External LLM CRUD grant for this field (contains C/R/U/D). NULL inherits ERBTables.External LLMCRUD.
  calc_erb_fields_admin_can_create(t.erb_field_id) AS admin_can_create,         -- Derived: AdminCRUD contains 'C' (BLANK when NULL = inherits table/role).
  calc_erb_fields_admin_can_read(t.erb_field_id) AS admin_can_read,             -- Derived: AdminCRUD contains 'R' (BLANK when NULL = inherits table/role).
  calc_erb_fields_admin_can_update(t.erb_field_id) AS admin_can_update,         -- Derived: AdminCRUD contains 'U' (BLANK when NULL = inherits table/role).
  calc_erb_fields_admin_can_delete(t.erb_field_id) AS admin_can_delete,         -- Derived: AdminCRUD contains 'D' (BLANK when NULL = inherits table/role).
  calc_erb_fields_manager_can_create(t.erb_field_id) AS manager_can_create,     -- Derived: ManagerCRUD contains 'C' (BLANK when NULL = inherits table/role).
  calc_erb_fields_manager_can_read(t.erb_field_id) AS manager_can_read,         -- Derived: ManagerCRUD contains 'R' (BLANK when NULL = inherits table/role).
  calc_erb_fields_manager_can_update(t.erb_field_id) AS manager_can_update,     -- Derived: ManagerCRUD contains 'U' (BLANK when NULL = inherits table/role).
  calc_erb_fields_manager_can_delete(t.erb_field_id) AS manager_can_delete,     -- Derived: ManagerCRUD contains 'D' (BLANK when NULL = inherits table/role).
  calc_erb_fields_representative_can_create(t.erb_field_id) AS representative_can_create,-- Derived: RepresentativeCRUD contains 'C' (BLANK when NULL = inherits table/role).
  calc_erb_fields_representative_can_read(t.erb_field_id) AS representative_can_read,-- Derived: RepresentativeCRUD contains 'R' (BLANK when NULL = inherits table/role).
  calc_erb_fields_representative_can_update(t.erb_field_id) AS representative_can_update,-- Derived: RepresentativeCRUD contains 'U' (BLANK when NULL = inherits table/role).
  calc_erb_fields_representative_can_delete(t.erb_field_id) AS representative_can_delete,-- Derived: RepresentativeCRUD contains 'D' (BLANK when NULL = inherits table/role).
  calc_erb_fields_external_llm_can_create(t.erb_field_id) AS external_llm_can_create,-- Derived: External LLMCRUD contains 'C' (BLANK when NULL = inherits table/role).
  calc_erb_fields_external_llm_can_read(t.erb_field_id) AS external_llm_can_read,-- Derived: External LLMCRUD contains 'R' (BLANK when NULL = inherits table/role).
  calc_erb_fields_external_llm_can_update(t.erb_field_id) AS external_llm_can_update,-- Derived: External LLMCRUD contains 'U' (BLANK when NULL = inherits table/role).
  calc_erb_fields_external_llm_can_delete(t.erb_field_id) AS external_llm_can_delete,-- Derived: External LLMCRUD contains 'D' (BLANK when NULL = inherits table/role).
  t.created_at,                                                                 -- Audit: when this row was first inserted. Auto-stamped by the audit trigger (now() on INSERT); immutable thereafter.
  t.created_by,                                                                 -- Audit: the OWNER — the JWT user (auth.email()) who created this row. Auto-stamped on INSERT; immutable thereafter. NULL for build-time seed rows (no signed-in user).
  t.modified_at,                                                                -- Audit: when this row was last written. Auto-stamped by the audit trigger (now() on every INSERT/UPDATE).
  t.modified_by,                                                                -- Audit: the JWT user (auth.email()) who last wrote this row. Auto-stamped on every INSERT/UPDATE.
  t.modified_by_model                                                           -- Audit: the AI model credited on the last save when an LLM made/assisted the change (e.g. "gpt-4o"). NULL for plain human writes. Read from the app.modified_by_model session GUC by the audit trigger. The owner (CreatedBy/ModifiedBy) is always the human JWT user, never a model.
FROM erb_fields t;

-- ----------------------------------------------------------------------------
-- vw_api_endpoints: View for APIEndpoints
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_api_endpoints CASCADE;
CREATE VIEW vw_api_endpoints WITH (security_invoker = ON) AS
SELECT
  t.api_endpoint_id,                                                            -- Slug PK, e.g. 'checklist-run-analysis'.
  calc_api_endpoints_name(t.api_endpoint_id) AS name,                           -- Echoes APIEndpointId.
  t.title,                                                                      -- Human-readable endpoint name.
  t.description,                                                                -- What the endpoint does.
  t.http_method,                                                                -- GET / POST / PUT / PATCH / DELETE.
  t.path,                                                                       -- URL path, e.g. '/api/checklists/:id/run-analysis'.
  t.endpoint_type,                                                              -- ACTION / RPC / REPORT / WEBHOOK / BATCH — distinguishes from standard CRUD.
  t.subject_table_name,                                                         -- Primary table this endpoint acts on (raw string convention; may be blank for cross-table actions).
  t.role_visibility,                                                            -- Comma-separated canonical roles allowed to call this endpoint (Admin / Manager / Representative / Operations).
  t.where_clause,                                                               -- Optional row-access policy applied to the endpoint's subject, mirroring ERBTables.{Role}WHERE.
  t.triggers_state_machine,                                                     -- StateMachineId this endpoint can advance, if any (convention string).
  t.status,                                                                     -- Lifecycle status (mirrors ERBFeatureStatuses keys). DESIGNED for not-yet-built.
  t.created_at,                                                                 -- Audit: when this row was first inserted. Auto-stamped by the audit trigger (now() on INSERT); immutable thereafter.
  t.created_by,                                                                 -- Audit: the OWNER — the JWT user (auth.email()) who created this row. Auto-stamped on INSERT; immutable thereafter. NULL for build-time seed rows (no signed-in user).
  t.modified_at,                                                                -- Audit: when this row was last written. Auto-stamped by the audit trigger (now() on every INSERT/UPDATE).
  t.modified_by,                                                                -- Audit: the JWT user (auth.email()) who last wrote this row. Auto-stamped on every INSERT/UPDATE.
  t.modified_by_model                                                           -- Audit: the AI model credited on the last save when an LLM made/assisted the change (e.g. "gpt-4o"). NULL for plain human writes. Read from the app.modified_by_model session GUC by the audit trigger. The owner (CreatedBy/ModifiedBy) is always the human JWT user, never a model.
FROM api_endpoints t;

-- ----------------------------------------------------------------------------
-- vw_subject_state_instances: View for SubjectStateInstances
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_subject_state_instances CASCADE;
CREATE VIEW vw_subject_state_instances WITH (security_invoker = ON) AS
SELECT
  t.subject_state_instance_id,                                                  -- PK: ssi-{subject-table}-{subject-id}-{state-key}-{sequence-index}.
  calc_subject_state_instances_name(t.subject_state_instance_id) AS name,       -- Echoes SubjectStateInstanceId.
  t.state_machine,                                                              -- FK -> StateMachines.StateMachineId.
  t.subject_table_name,                                                         -- Polymorphic table name, e.g. Citations or Hearings.
  t.subject_id,                                                                 -- Polymorphic PK of the subject row.
  t.state_key,                                                                  -- The machine state entered by this occupancy record.
  t.entered_at,                                                                 -- Timestamp when this state was entered.
  t.exited_at,                                                                  -- Timestamp when the subject left this state. NULL while current.
  t.sequence_index,                                                             -- 1-based position on this subject's path through the machine.
  t.prior_instance,                                                             -- Self-FK -> SubjectStateInstances.SubjectStateInstanceId — the previous occupancy in this subject's chain. NULL for the initial state.
  t.entered_via_transition,                                                     -- FK -> StateTransitions.StateTransitionId — the edge event that created this occupancy.
  calc_subject_state_instances_is_current(t.subject_state_instance_id) AS is_current,-- TRUE when ExitedAt IS NULL — this is the subject's active state.
  calc_subject_state_instances_has_complete_lineage(t.subject_state_instance_id) AS has_complete_lineage,-- TRUE when the PriorInstance chain walks back to SequenceIndex=1 (the initial state occupancy). Validates lineage completeness.
  t.created_at,                                                                 -- Audit: when this row was first inserted. Auto-stamped by the audit trigger (now() on INSERT); immutable thereafter.
  t.created_by,                                                                 -- Audit: the OWNER — the JWT user (auth.email()) who created this row. Auto-stamped on INSERT; immutable thereafter. NULL for build-time seed rows (no signed-in user).
  t.modified_at,                                                                -- Audit: when this row was last written. Auto-stamped by the audit trigger (now() on every INSERT/UPDATE).
  t.modified_by,                                                                -- Audit: the JWT user (auth.email()) who last wrote this row. Auto-stamped on every INSERT/UPDATE.
  t.modified_by_model                                                           -- Audit: the AI model credited on the last save when an LLM made/assisted the change (e.g. "gpt-4o"). NULL for plain human writes. Read from the app.modified_by_model session GUC by the audit trigger. The owner (CreatedBy/ModifiedBy) is always the human JWT user, never a model.
FROM subject_state_instances t;

-- ----------------------------------------------------------------------------
-- vw_violation_types: View for ViolationTypes
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_violation_types CASCADE;
CREATE VIEW vw_violation_types WITH (security_invoker = ON) AS
SELECT
  t.violation_type_id,                                                          -- Surrogate key for the violation type (off-screen).
  calc_violation_types_name(t.violation_type_id) AS name,                       -- Kebab-cased PK derived from the violation code (e.g. 'CVC-22350' -> 'cvc-22350').
  t.is_mock_data,                                                               -- TRUE for seed/demo rows; distinguishes mock data from real records.
  t.code,                                                                       -- Statute/vehicle-code reference for the violation, e.g. 'CVC-22350'.
  t.jurisdiction,                                                               -- FK to the Jurisdiction whose rules govern this violation type.
  calc_violation_types_jurisdiction_label(t.violation_type_id) AS jurisdiction_label,-- Display name of the governing jurisdiction.
  t.description,                                                                -- Plain-English description of the violation, e.g. 'Unsafe speed for conditions'.
  t.base_fine_usd,                                                              -- Base fine amount in USD for this violation before any penalties or reductions.
  t.points,                                                                     -- License points assessed for a conviction of this violation.
  calc_violation_types_traffic_school_point_cap(t.violation_type_id) AS traffic_school_point_cap,-- The governing jurisdiction's traffic-school point cap, looked up from Jurisdictions.
  calc_violation_types_is_school_eligible_by_cap(t.violation_type_id) AS is_school_eligible_by_cap,-- Whether this violation's points fall at or below the jurisdiction's traffic-school point cap (jurisdiction rule applied to the violation).
  t.citations,                                                                  -- Reverse FK: citations issued for this violation type.
  calc_violation_types_count_of_citations(t.violation_type_id) AS count_of_citations,-- Number of citations issued for this violation type.
  t.created_at,                                                                 -- Audit: when this row was first inserted. Auto-stamped by the audit trigger (now() on INSERT); immutable thereafter.
  t.created_by,                                                                 -- Audit: the OWNER — the JWT user (auth.email()) who created this row. Auto-stamped on INSERT; immutable thereafter. NULL for build-time seed rows (no signed-in user).
  t.modified_at,                                                                -- Audit: when this row was last written. Auto-stamped by the audit trigger (now() on every INSERT/UPDATE).
  t.modified_by,                                                                -- Audit: the JWT user (auth.email()) who last wrote this row. Auto-stamped on every INSERT/UPDATE.
  t.modified_by_model                                                           -- Audit: the AI model credited on the last save when an LLM made/assisted the change (e.g. "gpt-4o"). NULL for plain human writes. Read from the app.modified_by_model session GUC by the audit trigger. The owner (CreatedBy/ModifiedBy) is always the human JWT user, never a model.
FROM violation_types t;

-- ----------------------------------------------------------------------------
-- vw_drivers: View for Drivers
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_drivers CASCADE;
CREATE VIEW vw_drivers WITH (security_invoker = ON) AS
SELECT
  t.driver_id,                                                                  -- Surrogate key for the driver (off-screen).
  calc_drivers_name(t.driver_id) AS name,                                       -- Kebab-cased PK derived from the license number (e.g. 'D1234567' -> 'd1234567').
  t.is_mock_data,                                                               -- TRUE for seed/demo rows; distinguishes mock data from real records.
  t.license_number,                                                             -- Driver's license number; the natural identifier for the driver.
  t.first_name,                                                                 -- Driver's first name.
  t.last_name,                                                                  -- Driver's last name.
  calc_drivers_full_name(t.driver_id) AS full_name,                             -- Display name, last-comma-first.
  t.home_jurisdiction,                                                          -- FK to the Jurisdiction that issued the driver's license (governs point/suspension rules for the driver).
  calc_drivers_home_jurisdiction_label(t.driver_id) AS home_jurisdiction_label, -- Display name of the driver's home jurisdiction.
  calc_drivers_suspension_threshold(t.driver_id) AS suspension_threshold,       -- Point-suspension threshold pulled from the driver's home jurisdiction.
  calc_drivers_warning_threshold(t.driver_id) AS warning_threshold,             -- Point-warning threshold pulled from the driver's home jurisdiction.
  t.citations,                                                                  -- Reverse FK: citations issued to this driver.
  calc_drivers_count_of_citations(t.driver_id) AS count_of_citations,           -- Number of citations issued to this driver.
  calc_drivers_active_points(t.driver_id) AS active_points,                     -- Sum of license points across this driver's citations that resulted in a conviction (guilty/unpaid-default) and are still point-active.
  calc_drivers_license_status(t.driver_id) AS license_status,                   -- License-points state machine for the driver: Suspended at/above the suspension threshold, Warning at/above the warning threshold, otherwise Valid.
  t.created_at,                                                                 -- Audit: when this row was first inserted. Auto-stamped by the audit trigger (now() on INSERT); immutable thereafter.
  t.created_by,                                                                 -- Audit: the OWNER — the JWT user (auth.email()) who created this row. Auto-stamped on INSERT; immutable thereafter. NULL for build-time seed rows (no signed-in user).
  t.modified_at,                                                                -- Audit: when this row was last written. Auto-stamped by the audit trigger (now() on every INSERT/UPDATE).
  t.modified_by,                                                                -- Audit: the JWT user (auth.email()) who last wrote this row. Auto-stamped on every INSERT/UPDATE.
  t.modified_by_model                                                           -- Audit: the AI model credited on the last save when an LLM made/assisted the change (e.g. "gpt-4o"). NULL for plain human writes. Read from the app.modified_by_model session GUC by the audit trigger. The owner (CreatedBy/ModifiedBy) is always the human JWT user, never a model.
FROM drivers t;

-- ----------------------------------------------------------------------------
-- vw_citations: View for Citations
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_citations CASCADE;
CREATE VIEW vw_citations WITH (security_invoker = ON) AS
SELECT
  t.citation_id,                                                                -- Surrogate key for the citation (off-screen).
  calc_citations_name(t.citation_id) AS name,                                   -- Kebab-cased PK derived from the citation number (e.g. 'TC-2026-0001' -> 'tc-2026-0001').
  t.is_mock_data,                                                               -- TRUE for seed/demo rows; distinguishes mock data from real records.
  t.citation_number,                                                            -- Human citation/ticket number printed on the ticket.
  t.driver,                                                                     -- FK to the cited Driver.
  calc_citations_driver_label(t.citation_id) AS driver_label,                   -- Display name of the cited driver.
  t.violation_type,                                                             -- FK to the cited ViolationType.
  calc_citations_violation_label(t.citation_id) AS violation_label,             -- Description of the cited violation.
  t.jurisdiction,                                                               -- FK to the Jurisdiction in which the citation was issued (governs deadlines, penalties, points).
  calc_citations_jurisdiction_label(t.citation_id) AS jurisdiction_label,       -- Display name of the issuing jurisdiction.
  calc_citations_base_fine_usd(t.citation_id) AS base_fine_usd,                 -- Base fine for the cited violation, pulled from the ViolationType.
  calc_citations_violation_points(t.citation_id) AS violation_points,           -- License points for the cited violation, pulled from the ViolationType.
  t.issued_on,                                                                  -- Date the citation was issued to the driver.
  t.as_of_date,                                                                 -- The 'today' reference date used to evaluate deadlines for this citation (lets seed data exercise overdue/late states deterministically).
  t.responded_on,                                                               -- Date the driver responded (paid or requested a hearing). Null if no response yet.
  t.contest_requested,                                                          -- Whether the driver elected to contest the citation (request a hearing) rather than pay.
  t.paid_on,                                                                    -- Date the fine was paid in full. Null if not yet paid.
  t.amount_paid_usd,                                                            -- Total amount the driver has paid against this citation. Null/0 if nothing paid.
  calc_citations_days_to_respond(t.citation_id) AS days_to_respond,             -- Response window in days, pulled from the issuing jurisdiction.
  calc_citations_days_to_pay_after_ruling(t.citation_id) AS days_to_pay_after_ruling,-- Days-to-pay window, pulled from the issuing jurisdiction.
  calc_citations_late_penalty_pct(t.citation_id) AS late_penalty_pct,           -- Late-penalty percentage, pulled from the issuing jurisdiction.
  calc_citations_days_late_to_collections(t.citation_id) AS days_late_to_collections,-- Days-late-to-collections window, pulled from the issuing jurisdiction.
  calc_citations_response_due_date(t.citation_id) AS response_due_date,         -- Deadline to respond: IssuedOn + the jurisdiction's response window.
  calc_citations_days_until_response_due(t.citation_id) AS days_until_response_due,-- Days remaining (negative if overdue) until the response deadline, measured from AsOfDate.
  calc_citations_is_response_overdue(t.citation_id) AS is_response_overdue,     -- True when no response was filed and the response deadline has passed as of AsOfDate.
  calc_citations_count_of_hearings(t.citation_id) AS count_of_hearings,         -- Number of hearing records attached to this citation.
  calc_citations_latest_hearing_outcome(t.citation_id) AS latest_hearing_outcome,-- Outcome of the most recent hearing for this citation (Pending if a hearing exists but has no outcome; blank if no hearing).
  calc_citations_contest_status(t.citation_id) AS contest_status,               -- Contest/Hearing state machine: NotContested when the driver did not elect to contest; otherwise HearingRequested -> Scheduled -> Heard, reflected from the latest hearing's outcome.
  calc_citations_is_dismissed(t.citation_id) AS is_dismissed,                   -- True when the latest hearing outcome dismissed the citation.
  calc_citations_is_guilty(t.citation_id) AS is_guilty,                         -- True when the driver is liable: either found guilty/upheld at hearing, or defaulted by missing the response deadline without contesting.
  calc_citations_amount_due_usd(t.citation_id) AS amount_due_usd,               -- Amount currently owed: 0 if dismissed; otherwise the base fine plus the jurisdiction's late penalty if the payment is late.
  calc_citations_payment_due_date(t.citation_id) AS payment_due_date,           -- Date the fine is due: the later anchor (response deadline) plus the jurisdiction's days-to-pay window.
  calc_citations_is_payment_late(t.citation_id) AS is_payment_late,             -- True when the driver is liable, has not paid in full, and the payment due date has passed as of AsOfDate.
  calc_citations_is_in_collections(t.citation_id) AS is_in_collections,         -- True when a late payment has remained unpaid past the jurisdiction's collections window.
  calc_citations_payment_status(t.citation_id) AS payment_status,               -- Payment/Penalty state machine: NotOwed (dismissed) -> Paid -> Collections -> Late -> Due. Evaluated in priority order.
  calc_citations_effective_points(t.citation_id) AS effective_points,           -- License points this citation actually contributes to the driver: the violation's points if the driver is liable and not dismissed, otherwise 0. Drives the driver's ActivePoints rollup.
  calc_citations_citation_status(t.citation_id) AS citation_status,             -- Citation lifecycle state machine: Issued -> Responded -> InContest -> Adjudicated -> Closed. The top-level status synthesizing the other tracks.
  t.hearings,                                                                   -- Reverse FK: hearing records for this citation.
  t.payments,                                                                   -- Reverse FK: payment records for this citation.
  t.case_events,                                                                -- Reverse FK: append-only case-event log entries for this citation.
  t.created_at,                                                                 -- Audit: when this row was first inserted. Auto-stamped by the audit trigger (now() on INSERT); immutable thereafter.
  t.created_by,                                                                 -- Audit: the OWNER — the JWT user (auth.email()) who created this row. Auto-stamped on INSERT; immutable thereafter. NULL for build-time seed rows (no signed-in user).
  t.modified_at,                                                                -- Audit: when this row was last written. Auto-stamped by the audit trigger (now() on every INSERT/UPDATE).
  t.modified_by,                                                                -- Audit: the JWT user (auth.email()) who last wrote this row. Auto-stamped on every INSERT/UPDATE.
  t.modified_by_model                                                           -- Audit: the AI model credited on the last save when an LLM made/assisted the change (e.g. "gpt-4o"). NULL for plain human writes. Read from the app.modified_by_model session GUC by the audit trigger. The owner (CreatedBy/ModifiedBy) is always the human JWT user, never a model.
FROM citations t;

